import { getConfig } from "./config.js";
import { McpProxy } from "./mcpProxy.js";
/**
 * Build an McpClient bound to the active config. Reads `getConfig()` once at
 * construction (matching the previous per-runner behavior), so a command's
 * whole run uses a single config snapshot.
 */
export function createMcpClient(platform, pluginVersion) {
    const proxy = new McpProxy(platform, pluginVersion);
    const config = getConfig();
    return {
        call: (tool, args) => proxy.toolCall(config, tool, args),
        ensureSession: () => proxy.ensureSession(config),
        serviceUrl: config.serviceUrl,
    };
}
